CREATE SEQUENCE IF NOT EXISTS gnss_measurements_id_seq;

CREATE TABLE "gnss_measurements" (
    "Id" bigint NOT NULL DEFAULT nextval('gnss_measurements_id_seq'),
    "CompanyId" bigint NOT NULL,
    "UserId" bigint NOT NULL,
    "DeviceId" text NOT NULL,
    "BatchId" text NOT NULL,
    "CapturedAtUtc" timestamp with time zone NOT NULL,
    "ElapsedRealtimeNanos" bigint NOT NULL,
    "DataAvailable" boolean NOT NULL,
    "UnavailableReason" integer NULL,
    "NetworkTimeUtc" timestamp with time zone NULL,
    "NetworkTimeSynced" boolean NOT NULL,
    "GnssTimeUtcMs" bigint NULL,
    "HardwareClockDiscontinuityCount" integer NULL,
    "PrimaryAvgCn0DbHz" double precision NULL,
    "PrimaryAgcDb" double precision NULL,
    "PrimaryBandKey" text NULL,
    "VisibleSatelliteCount" integer NULL,
    "Latitude" double precision NULL,
    "Longitude" double precision NULL,
    "Geohash7" text NULL,
    "SpeedMps" double precision NULL,
    "BearingDeg" double precision NULL,
    "AccuracyM" double precision NULL,
    "AltitudeM" double precision NULL,
    "Provider" text NULL,
    "MeasurementsSupported" boolean NOT NULL,
    "AgcSupported" boolean NOT NULL,
    "GpsProviderEnabled" boolean NOT NULL,
    "IsFullTracking" boolean NULL,
    "ConfigVersion" integer NOT NULL,
    "UploadReason" integer NOT NULL,
    "IsAnomaly" boolean NOT NULL,
    "AnomalyType" integer NULL,
    "InWhitelistZone" boolean NOT NULL,
    "TimeSkewWarning" boolean NOT NULL,
    "Bands" jsonb NULL,
    "ReceivedAt" timestamp with time zone NOT NULL,
    CONSTRAINT "PK_gnss_measurements" PRIMARY KEY ("Id", "CapturedAtUtc")
) PARTITION BY RANGE ("CapturedAtUtc");

