    ON "gnss_measurements" ("DeviceId", "CapturedAtUtc");
CREATE INDEX "IX_gnss_measurements_anomaly"
    ON "gnss_measurements" ("CapturedAtUtc") WHERE "IsAnomaly";

-- Create the current and next ISO-week partitions so ingest works immediately.
-- Deterministic-at-apply-time: computed from the ISO-week Monday of now() in UTC, so the boundary
-- matches GnssPartitionMaintenanceJob (which plans weeks from DateTime.UtcNow) regardless of the
-- DB session time zone — otherwise the two could disagree and the job would overlap a partition.
DO $$
DECLARE
    wk_start date := date_trunc('week', now() AT TIME ZONE 'UTC')::date;
    wk_next  date := wk_start + 7;
    wk_after date := wk_start + 14;
    p_curr   text := 'gnss_measurements_' || to_char(wk_start, 'IYYY_"w"IW');
    p_next   text := 'gnss_measurements_' || to_char(wk_next,  'IYYY_"w"IW');
BEGIN
    EXECUTE format(
        'CREATE TABLE IF NOT EXISTS %I PARTITION OF "gnss_measurements" FOR VALUES FROM (%L) TO (%L);',
        p_curr, wk_start::text, wk_next::text);
    EXECUTE format(
        'CREATE TABLE IF NOT EXISTS %I PARTITION OF "gnss_measurements" FOR VALUES FROM (%L) TO (%L);',
        p_next, wk_next::text, wk_after::text);
END $$;


